    const n = nums.length;
    const answer = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Determine the parity of nums[i]. 0 for even, 1 for odd.
        const parityI = nums[i] % 2;
        let count = 0;

        // Check all subsequent elements j > i
        for (let j = i + 1; j < n; j++) {
